insert into stock_recipes (slug, title, "desc", type, week, base_macros, steps, freezer_tips, scaling_tip, position) values
  ('bagel', 'Blueberry Breakfast Bagel Sandwich', 'A fiber-packed delicious Sola Blueberry Bagel sandwich featuring waffled liquid egg whites and Greek cottage cheese shmear.', 'Breakfast', '{1,2}'::int[], '{"cal":205,"prot":31.5,"fat":4.2,"fib":28,"carb":36.5}'::jsonb, ARRAY['Preheat mini waffle maker. Coat top and bottom grids with avocado oil spray.','Measure out exactly 120g of liquid egg whites.','Slowly pour egg whites onto bottom grid, ensuring it does not overflow.','Close and let cook undisturbed for 2-3 minutes until set and steam slows.','Toast your Sola Blueberry Bagel. Spread cottage cheese evenly on both sides.','Assemble waffled egg white patty into Sola Blueberry Bagel and enjoy immediately.']::text[], 'Wrap Sola Blueberry Bagels and cooked waffled egg white patties separately in airtight plastic wrap. Toast the bagel straight from frozen, and microwave the egg white patty on high for 30-45 seconds.', null, 0),
  ('vegStirfry', 'Vegetable & Egg White Stir Fry', 'A high-volume lunch stir-fry packed with edamame, fresh broccoli, and onions, served with your real white/black rice mixture.', 'Lunch', '{1}'::int[], '{"cal":765,"prot":73,"fat":18,"fib":15.6,"carb":58}'::jsonb, ARRAY['Cook the scaled white and black rice mixture together in a small pot or rice cooker on Sunday.','In your largest wok, sauté the chopped mushrooms, garlic, and onions with sesame oil until fragrant and caramelized.','Add broccoli, chopped carrots, and 3 tbsp of water. Cover and let steam for 4 minutes.','Toss in edamame and continue cooking on high heat.','In a separate non-stick skillet, scramble your egg whites in batches until they form firm curds.','Mix Gochujang and coconut aminos. Combine the firm curds with the vegetable base, drizzle the sauce, and toss on high for 2 minutes.']::text[], 'Freeze in solid plastic meal prep containers for up to 3 months. To reheat, microwave directly from frozen on medium-high for 3 minutes, stir, and microwave for another 1-2 minutes until steaming.', null, 1),
  ('tofuStirfry', 'Tofu & Egg White Stir-Fry', 'An ultimate zero-waste high-volume dinner utilizing firm extra-firm tofu chunks, veggies, and egg whites. Perfect for meal prep and freezing, with a delicious gochujang-soy glaze.', 'Dinner', '{1}'::int[], '{"cal":662,"prot":54.1,"fat":22,"fib":6,"carb":31}'::jsonb, ARRAY['Cook white and black rice blend together.','Drain and pat dry extra-firm tofu. Sauté the tofu cubes in a large wok with oil until golden brown.','In corporate the broccoli and edamame. Sauté on medium with a splash of water, then cover and steam for 3 minutes.','Push vegetables to the sides. Pour egg whites in the center; cook and scramble until firm.','Combine Gochujang and soy sauce, pour over the mixture, and toss on high heat for 2 minutes to glaze.']::text[], 'Freezing extra-firm tofu gives it a highly enjoyable sponge-like, chewy texture. Store prepped bowls in the freezer. To reheat, microwave with a damp paper towel on top to retain maximum moisture.', null, 2),
  ('blondies', '9x13" Pan Protein Blondies', 'A dense high-protein vanilla choc-chip blondie baked in a standard 9x13 pan. Sliced into exactly 24 even 2x2" squares (eat 1 daily).', 'Dessert', '{1,3}'::int[], '{"cal":88,"prot":9.6,"fat":1.8,"fib":1,"carb":9.3}'::jsonb, ARRAY['Tip: Enter 24 servings in the multiplier to see the exact ingredients needed for a full 9x13" pan!','Preheat oven to 350°F (175°C). Line a standard 9x13" baking pan with parchment paper.','Whisk together yogurt, whole eggs, liquid egg whites, and vanilla extract.','In a separate bowl, whisk all-purpose flour, protein powder, oat flour, Swerve, baking soda, and salt.','Combine wet and dry bases. Mix thoroughly with a spatula to form a thick uniform batter, then fold in chocolate chips.','Spread evenly in the pan and bake for 22-25 minutes. Cool completely and slice into exactly 24 squares (6x4 grid).']::text[], 'Once completely cooled, wrap individual 2x2" squares tightly in plastic wrap. Freeze in a single layer. They thaw perfectly at room temperature in 10-15 minutes or inside your lunchbox by mid-day.', 'Scale to 24x to output ingredients for exactly 1 full 9x13" pan.', 3),
  ('mapoTofu', 'Vegetarian Mapo Tofu', 'A high-volume Sichuan classic utilizing minced shiitakes, firm tofu, and a silky egg white base.', 'Lunch', '{2}'::int[], '{"cal":757,"prot":61.5,"fat":25,"fib":9,"carb":37.8}'::jsonb, ARRAY['Cook your white and black rice blend.','Sauté minced mushrooms, garlic, and ginger with sesame oil until browned and highly fragrant.','Add Doubanjiang and crushed Sichuan peppercorns, cooking for 30 seconds to release aromatic red oils.','Push mushrooms to the side, pour in egg whites, let them set into firm curds, and scramble.','Fold in your cubed extra-firm tofu and soy sauce mixed with 1/2 cup of water. Simmer on high until thickened.']::text[], 'The spicy bean paste (Doubanjiang) and Sichuan peppercorns freeze exceptionally well without losing depth. Pack tightly into small flat containers. Microwave from frozen for 2.5 minutes on medium-high.', null, 4),
  ('silkyTofu', 'Soft Tofu with Silky Egg Sauce', 'Air-fried extra-firm tofu cubes layered over a rich, soft-stirred egg white vegetable sauce.', 'Dinner', '{2}'::int[], '{"cal":684,"prot":57.1,"fat":22.3,"fib":7.2,"carb":36}'::jsonb, ARRAY['Air-fry the cubed extra-firm tofu at 400°F (200°C) for 12-15 minutes until golden.','Cook your white/black rice mixture.','Sauté sliced mushrooms, garlic, and ginger in a large pan with a splash of water and sesame oil.','Push vegetables to the side. Pour in egg whites, stirring constantly to mimic soft, velvety silky scrambled curds.','Whisk soy sauce, oyster sauce, cornstarch, and water together. Pour over the eggs, add tofu cubes, and simmer until glazed.']::text[], 'Make sure to let the dish cool 100% to room temp before sealing to prevent condensation-induced ice crystals. If reheating at work, stir midway to recombine the velvety cornstarch slurry.', null, 5),
  ('pudding', 'Double Chocolate Protein Pudding', 'A rich chocolate post-workout snack utilizing fat-free Greek yogurt and high quality cocoa. Rounded to 0.25x portion.', 'Dessert', '{2}'::int[], '{"cal":74,"prot":11,"fat":1.8,"fib":0.5,"carb":3.5}'::jsonb, ARRAY['Add all dry ingredients (protein powder, dark cocoa, pinch of sea salt) into a small jar or bowl.','Whisk together with the fat-free vanilla Greek yogurt until smooth and lump-free.','Cover and store in the refrigerator to allow the cocoa powder to fully hydrate for 15 minutes before serving.','Top with chocolate chips and enjoy.']::text[], 'Due to the dairy base, do not freeze this dish solid as it will split. Instead, store it tightly in small jars inside the refrigerator. It stays completely fresh and smooth for up to 5 days.', null, 6),
  ('pancakes', 'Protein Pancakes', 'A clean low-fat breakfast utilizing whole eggs, Greek yogurt, and high quality vanilla whey.', 'Breakfast', '{3}'::int[], '{"cal":183,"prot":28,"fat":5,"fib":1,"carb":5.5}'::jsonb, ARRAY['Whisk eggs and nonfat Greek yogurt together in a medium bowl until smooth.','Fold in whey protein, baking powder, and monk fruit sweetener.','Heat a non-stick griddle over medium-low heat. Spray with light oil spray.','Spoon small dollops of batter onto the hot surface. Cook until bubbles form around the edges.','Carefully flip and cook for an additional minute until fluffy and fully set.']::text[], 'Stack cooked pancakes with sheets of parchment paper in between to prevent sticking. Seal in a freezer bag. Pop frozen pancakes straight into a toaster on a medium setting for a quick hot breakfast!', null, 7),
  ('curryLunch', 'Curry Bread Pocket Bento Box', 'A complete lunch system featuring two waffled curry bread pockets (4 slices of high-protein bread, with spinach folded into the filling) and a Tamagoyaki side.', 'Lunch', '{3}'::int[], '{"cal":778,"prot":80.1,"fat":26.1,"fib":21.8,"carb":66.6}'::jsonb, ARRAY['Trim the crusts/edges off the high-protein bread slices. Air-fry just the trimmed crusts at 300°F (150°C) until completely dry, then process them into breadcrumbs. Reserve the bread centers for the pockets.','Boil diced potato and carrot. Drain, then stir in the curry cube, fresh spinach, and liquid egg whites. Scramble over heat until the spinach wilts down and a thick, scoopable paste forms.','Divide the curry filling between the reserved bread centers (4 trimmed slices = 2 pockets), crimp each pocket shut, dip in egg wash, coat in the crust breadcrumbs, and air-fry raw at 350°F (175°C) until crispy.','Whisk whole eggs and cook layers in a pan, folding progressively into a log to form a classic Japanese Tamagoyaki.']::text[], 'Freeze Curry bread pockets RAW (before air frying). This prevents soggy structures. Air-fry from frozen at 350°F (175°C) for 10-12 minutes. Store cooked Tamagoyaki logs wrapped tightly, thaw in fridge.', null, 8),
  ('tofuPatties', 'Crispy Tofu Patties', 'Air-fried edamame-tofu patties over scrambled egg whites, accompanied by a cilantro-jalapeno cream sauce.', 'Dinner', '{3}'::int[], '{"cal":691,"prot":63,"fat":25,"fib":7.5,"carb":22.5}'::jsonb, ARRAY['Drain tofu, press thoroughly, and mash together with edamame, almond flour, cornstarch, and 50g of egg whites.','Form into patties and air-fry at 375°F (190°C) for 10-12 minutes, flip, and air-fry for 5-8 more minutes.','Scramble the remaining egg whites in a skillet until fully set.','Blend Greek yogurt, cilantro, jalapeños, garlic, and a splash of lime juice until smooth and creamy.','Plate the crispy patties over the set egg-white scramble, drizzle with sauce, and enjoy.']::text[], 'Air-fry the patties fully before freezing. Store in airtight Ziplocs with parchment paper separating them. Reheat in an air fryer at 350°F (175°C) for 6 minutes to restore crispiness.', null, 9),
  ('frittata', 'Egg White Veggie Frittata', 'A dense skillet-baked egg white wedge loaded with roasted broccoli florets and mushrooms.', 'Breakfast', '{4}'::int[], '{"cal":153,"prot":16.5,"fat":6.8,"fib":2,"carb":6.5}'::jsonb, ARRAY['Sauté onions and vegetables in olive oil in an oven-safe skillet until fully tender and moisture is completely evaporated.','Whisk liquid egg whites with salt, pepper, and Parmesan cheese.','Pour egg whites evenly over the vegetables in the pan.','Cook on low heat undisturbed for 10 minutes until edges are set.','Pop under the oven broiler for 2-3 minutes until the top is puffed and deeply golden.']::text[], 'Let the frittata cool 100% to room temperature before wrapping in plastic wrap to prevent trapped condensation. When microwaving at work, wrap tightly in a dry paper towel to catch any escaping moisture.', null, 10),
  ('ramen', 'Spicy Ramen-Style Tofu Soup', 'Hearty extra-firm tofu blocks and real black/white rice simmered in a hot Gochujang spinach broth, topped with soft scrambled egg whites.', 'Lunch', '{4}'::int[], '{"cal":689,"prot":62.8,"fat":14,"fib":12,"carb":39.4}'::jsonb, ARRAY['Cut the extra-firm tofu into bite-size blocks and pan-sear (or air-fry) until lightly golden and firm.','Cook your white/black rice mixture.','Sauté minced garlic and ginger. Whisk in Gochujang, soy sauce, and vegetable broth; simmer.','Add your rice and fresh spinach to the broth and cook until spinach is wilted.','Scramble egg whites separately in a skillet until velvety.','Drop the tofu blocks into the broth to warm through, then divide into containers with the egg whites and store.']::text[], 'Divide the broth and tofu blocks into separate airtight layers if possible. Freeze broth solid. To serve, defrost in microwave on high for 2 minutes, stir, then heat for an additional 1.5 minutes.', null, 11),
  ('laab', 'Vegan Tofu Laab', 'Finely crumbled extra-firm tofu tossed with toasted jasmine rice powder and lemongrass in a lime-tamari dressing. Rounded to a 0.85x portion.', 'Dinner', '{4}'::int[], '{"cal":779,"prot":37.4,"fat":29.3,"fib":6.8,"carb":35.1}'::jsonb, ARRAY['Sauté uncooked jasmine rice dry until golden and nutty, then crush into a coarse powder.','Whisk lime juice, brown sugar, soy sauce, and chili flakes in a bowl.','Crumble extra-firm tofu into small chunks.','Sauté lemongrass and sliced shallots in oil, add tofu, and cook until slightly crispy.','Toss base with the dressing, toasted rice powder, and fresh herbs; serve on butter lettuce.']::text[], 'Freeze the cooked tofu and aromatic lemongrass base dry on Sunday. Prepare your lime dressing separately. When ready to eat, thaw and reheat the tofu in a hot pan for 2 mins, then toss with the fresh dressing and fresh mint.', null, 12),
  ('mugcake', 'Protein Mug Cake', 'A dense personal cake cooked on-demand, featuring a molten dark chocolate chip center.', 'Dessert', '{4}'::int[], '{"cal":99,"prot":10.4,"fat":3.4,"fib":3,"carb":11}'::jsonb, ARRAY['Mix cocoa powder, oat flour, whey protein, and baking powder together in a jar.','When ready to bake, scoop dry base into a mug, add syrup and almond milk, and stir until completely smooth.','Push dark chocolate chips into the center of the batter.','Drop microwave power level to 70% to prevent dry seizing.','Microwave for 50-60 seconds (it should look slightly wet on the top), let rest for 1 minute, and serve.']::text[], 'Do not cook and freeze this cake! Instead, pre-mix the dry base in a mason jar. When you want a sweet treat, scoop out 4.5 tablespoons, add your wet ingredients, and microwave on-demand.', null, 13),
  ('eggSkillet', 'Spiced Tomato & Egg Skillet', 'A spiced baked-egg skillet over fingerling potatoes in a tomato, poblano & jalapeño sauce. Amounts shown are PER SERVING — scale to 6x in the Recipe Scaler to make the full 6-serving bake.', 'Breakfast', '{}'::int[], '{"cal":195,"prot":9.6,"fat":5,"fib":4.5,"carb":30}'::jsonb, ARRAY['PREP POTATOES: Boil potatoes in generously salted water until tender (~20 min for the full batch). Drain, cool slightly, and slice into 1/2-inch rounds.','SAUTE AROMATICS: Coat a large skillet with cooking spray over medium-high heat. Cook onion until almost tender (5-7 min). Add poblano and jalapeño; cook 3 min. Add ginger, garlic, cumin, garam masala, and coriander; cook 1 min until fragrant.','SIMMER SAUCE: Stir in the canned tomatoes and a little salt. Simmer on medium-low, breaking up the tomatoes with a fork, for 15 min. Stir in the mint and cilantro/basil; taste and adjust seasoning.','BAKE: Heat oven to 375°F. Arrange the potatoes in a single layer in a baking dish (9-inch square for the full 6-serving batch) and pour the hot sauce over them.','FINISH: Make one well per serving, crack an egg into each, and season with salt and pepper. Bake 8-13 min until whites are set but yolks stay runny. Garnish with extra herbs.']::text[], 'Best eaten fresh, but the spiced tomato-potato base freezes well WITHOUT the eggs. Freeze the sauce-and-potato base in portions; thaw, spread in a dish, then crack in fresh eggs and bake just before serving.', null, 14),
  ('proteinIceCream', 'Cottage Cheese Chocolate Protein Ice Cream', 'A Ninja Creami high-protein chocolate ice cream from cottage cheese + Fairlife chocolate milk. Amounts shown are PER SERVING (1/2 pint) — scale to 2x in the Recipe Scaler for the full 1-pint batch.', 'Dessert', '{}'::int[], '{"cal":171,"prot":26,"fat":3,"fib":1,"carb":17}'::jsonb, ARRAY['BLEND: Add the cottage cheese, chocolate milk, and protein powder to a high-speed blender. Blend until completely smooth with no curds remaining.','FREEZE: Pour into a Ninja Creami pint container, attach the lid, and freeze on a level surface for 18-24 hours.','FIRST SPIN: Lock the frozen pint into the outer bowl, load the machine, and run the "Ice Cream" (or "Lite Ice Cream") cycle.','RE-SPIN: If the texture looks powdery or crumbly, add 1 tbsp chocolate milk to the center and run "Re-spin" until creamy.','MIX-INS: Hollow out a channel down the center, add the crushed gluten-free Oreos (or chips / M&Ms), and run the "Mix-in" cycle. Serve immediately.']::text[], 'For leftovers, smooth the surface flat, put the lid on, and freeze up to 4 days. To finish later: lock the frozen pint back into the Creami, pour 1 tbsp chocolate milk on top, and run "Re-spin" to friction-thaw to soft-serve (do not scoop straight from the freezer).', null, 15);
